+            .map(|_| {
+                let mut direction: Vec<f64> = (0..dim)
+                    .map(|_| rng.sample(StandardNormal))
+                    .collect();
+
+                // Normalize to unit vector
+                let norm: f64 = direction.iter().map(|&x| x * x).sum::<f64>().sqrt();
