+    /// Project points onto a direction (SIMD-friendly dot product)
+    #[inline(always)]
+    fn project(points: &[Vec<f64>], direction: &[f64]) -> Vec<f64> {
+        points
+            .iter()
+            .map(|p| Self::dot_product(p, direction))
