+    /// Project points into pre-allocated buffer (reduces allocations)
+    #[inline(always)]
+    fn project_into(points: &[Vec<f64>], direction: &[f64], out: &mut [f64]) {
+        for (i, p) in points.iter().enumerate() {
+            out[i] = Self::dot_product(p, direction);
+        }
+    }
