+            if max_violation < self.tolerance {
+                let value: f64 = (0..n * n).map(|k| problem.c[k] * x[k]).sum();
+                return SDPSolution {
+                    x,
+                    value,
+                    status: SDPStatus::Optimal,
+                    iterations: iter + 1,
+                };
+            }
+        }
+
+        let value: f64 = (0..n * n).map(|k| problem.c[k] * x[k]).sum();
+        SDPSolution {
+            x,
+            value,
+            status: SDPStatus::MaxIterations,
+            iterations: self.max_iters,
+        }
+    }
