+        // by adding αI where α makes smallest eigenvalue ≥ 0
+
+        // Estimate smallest eigenvalue via power iteration on -X + λ_max I
+        let mut v: Vec<f64> = (0..n).map(|i| 1.0 / (n as f64).sqrt()).collect();
