+                }
+            }
+            let norm: f64 = y.iter().map(|&yi| yi * yi).sum::<f64>().sqrt();
+            lambda_max = v.iter().zip(y.iter()).map(|(&vi, &yi)| vi * yi).sum();
+            if norm > 1e-15 {
