+    /// Spherical exponential map
+    fn spherical_exp_map(&self, x: &[f64], v: &[f64]) -> Result<Vec<f64>> {
+        let v_norm = norm(v);
+
+        if v_norm < EPS {
+            return Ok(x.to_vec());
+        }
+
+        let cos_t = v_norm.cos();
+        let sin_t = v_norm.sin();
